/**
 * Function: Test node closure functionality
 *
 * @param nodeName Name for the observer node
 * @return bool Whether node closure worked correctly (relationships cleaned up)
 */
bool test_node_closure(const std::string& nodeName) {
    // 1. Create observer node
    auto observerNode = std::make_shared<TestObserverClosure>(nodeName);

    // 2. Get observer graph instance
    auto& observerGraph = reaction::ObserverGraph::getInstance();

    // 3. Add observer node to graph
    observerGraph.addNode(observerNode);

    // 4. Create source node for testing
    auto sourceNode = std::make_shared<reaction::ObserverNode>("source");
    observerGraph.addNode(sourceNode);

    // 5. Add observer relationship
    observerGraph.addObserverRelationship(sourceNode, observerNode);

    // 6. Verify initial state
    if (!observerGraph.hasNode(nodeName)) {
        return false;
    }

    // 7. Notify target and verify observer was notified
    sourceNode->valueChanged();
    if (!observerNode->wasChanged()) {
        return false;
    }

    // 8. Reset observer state
    observerNode->valueChanged(false);

    // 9. Close observer node
    observerGraph.closeNode(nodeName);

    // 10. Notify target again
    sourceNode->valueChanged();

    // 11. Verify observer was not notified after closure
    if (observerNode->wasChanged()) {
        return false;
    }

    // 12. Verify node is removed from graph
    if (observerGraph.hasNode(nodeName)) {
        return false;
    }

    // 13. Return success status
    return true;
}

}  // namespace test_reaction

