 */
std::tuple<std::string, int, int> test_filter_trigger(double initialValue,
                                                      double firstUpdate,
                                                      double secondUpdate,
                                                      double diffThreshold,
                                                      double levelThreshold) {
    using namespace reaction;

    // 1. Create reactive variable for sensor data
    auto sensor = var(initialValue).setName("sensor");

    // 2. Create variables to track recomputation count and last processed value
    auto recomputeCount = var(0).setName("recomputeCount");
    auto lastProcessedValue = var(initialValue).setName("lastProcessedValue");

    // 3. Create filter-triggered calculation
    auto filterCalc = calc([](double currentValue, double lastValue, int& count) {
        // Increment recompute count when calculation runs
        count++;
        return true; // Always recompute for this test
    }, sensor, lastProcessedValue, recomputeCount).setName("filterCalc");

    // 4. Apply filter based on difference threshold
    auto filterTrigger = filterCalc.filter([](double current, double last, double threshold) {
        return std::abs(current - last) > threshold;
    }, sensor, lastProcessedValue, diffThreshold);

    // 5. Create status calculation that depends on filter trigger
    auto statusCalc = calc([](bool filterPassed, double value, double levelThresh) -> std::string {
        if (value > levelThresh) {
            return "HIGH";
        } else if (value < -levelThresh) {
            return "LOW";
        } else {
            return "NORMAL";
        }
    }, filterTrigger, sensor, levelThreshold).setName("statusCalc");

    // Track initial state
    int firstRecomputeCount = recomputeCount.get();

    // 6. Update sensor with first value
    sensor.value(firstUpdate);

    // 7. Record recompute count after first update
    int firstUpdateRecomputeCount = recomputeCount.get();

    // 8. Update sensor with second value
    sensor.value(secondUpdate);

    // 9. Record recompute count after second update
    int secondUpdateRecomputeCount = recomputeCount.get();

    // 10. Get final status
    std::string finalStatus = statusCalc.get();

    // Update last processed value for next use
    lastProcessedValue.value(sensor.get());

    return std::make_tuple(finalStatus, firstUpdateRecomputeCount, secondUpdateRecomputeCount);
}

}  // namespace test_reaction
