    auto &tm = ThreadManager::getInstance();
    tm.resetForTesting();

    tm.registerThread();
    const std::size_t countAfterRegister = tm.getThreadCount();
    const bool safetyBeforeEnable = tm.isThreadSafetyEnabled();

