    const bool safetyAfterReset = tm.isThreadSafetyEnabled();

    return ThreadSafetyTransition{
        .beforeEnable = safetyBeforeEnable,
        .afterEnable = safetyAfterEnable,
        .afterReset = safetyAfterReset,
        .threadCount = countAfterRegister,
    };
}

