 */
ThreadGuardState test_thread_guard() {
    using namespace reaction;

    auto &tm = ThreadManager::getInstance();
    tm.resetForTesting();

    const bool safetyBefore = tm.isThreadSafetyEnabled();
    const std::size_t countBefore = tm.getThreadCount();

    std::thread worker([]() {
